sql:
SELECT report_id, user_id, access_date, access_type
FROM report_access_logs
WHERE access_date >= '2023-01-01' AND access_date <= '2023-03-31';

SELECT COUNT(DISTINCT year) AS total_years_analyzed
FROM (
    SELECT year FROM economic_indicators
    UNION
    SELECT year_id FROM data_quality_logs
) AS combined_years;

SELECT government_spending 
FROM economic_indicators 
WHERE year = 1981;

SELECT year, gdp 
FROM economic_indicators 
ORDER BY year;

SELECT year
FROM economic_indicators
WHERE consumer_spending > (SELECT AVG(consumer_spending) FROM economic_indicators);

SELECT year
FROM economic_indicators
WHERE consumer_spending = (SELECT MAX(consumer_spending) FROM economic_indicators);

external_knowledge:
- 'Best economic performance' refers to the highest GDP, lowest inflation rate, and lowest unemployment rate;
- 'High data quality' is defined as an average quality check result greater than 0.5;
- 'Popular reports' means the report has been downloaded more than 10 times;
- 'Active creators' indicates the user who created the report has more than 20 access events.

- "generous" refers to the year with the highest average spending per person;
- "average spending per person" is calculated as the total of consumer, government, and investment spending divided by the population;
- "reached its peak" means the year with the highest value.

- "Watered each flower" refers to accessing the report;
- "Tended to it" refers to the total number of accesses;
- "View its beauty" refers to the number of views;
- "Take its essence home" refers to the number of downloads;
- "Garden of published reports" refers to the collection of reports with a status of 'published'.
